import numpy as np

class NearestCentroidClassifier:
 def __init__(self, shrinkage_parameter=0.0):
 self.shrinkage = shrinkage_parameter
 self.centroids = {}
 self.global_mean = None

 def fit(self, X, y):
 # Compute class centroids
 classes = np.unique(y)
 for c in classes:
 X_c = X[y == c]
 self.centroids[c] = np.mean(X_c, axis=0)

 # Compute global mean for shrinkage
 self.global_mean = np.mean(X, axis=0)

 # Apply shrinkage if specified
 if self.shrinkage > 0:
 for c in self.centroids:
 self.centroids[c] = (1 - self.shrinkage) * self.centroids[c] + \
 self.shrinkage * self.global_mean

 def predict(self, X):
 predictions = []
 for x in X:
 distances = {}
 for c, centroid in self.centroids.items():
 distances[c] = np.linalg.norm(x - centroid) # Euclidean
 predictions.append(min(distances, key=distances.get))
 return np.array(predictions)

import numpy as np
from sklearn.preprocessing import normalize

class CosineNearestCentroid:
 def __init__(self, use_l2_normalize=True):
 self.use_l2 = use_l2_normalize
 self.centroids = {}

 def fit(self, X, y):
 classes = np.unique(y)
 for c in classes:
 X_c = X[y == c]
 centroid = np.mean(X_c, axis=0)
 if self.use_l2:
 centroid = centroid / np.linalg.norm(centroid)
 self.centroids[c] = centroid

 def predict(self, X):
 predictions = []
 for x in X:
 if self.use_l2:
 x_norm = x / np.linalg.norm(x)
 else:
 x_norm = x

 similarities = {}
 for c, centroid in self.centroids.items():
 # Cosine similarity = dot product for normalized vectors
 similarities[c] = np.dot(x_norm, centroid)

 # Assign to class with highest cosine similarity
 predictions.append(max(similarities, key=similarities.get))
 return np.array(predictions)
